INSERT INTO "discovery_architecture_objects" ("id", "architecture_id", "object_id", "created_at") VALUES (34, 12, 51, '2026-03-23T13:57:17.797Z') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_architectures" ("id", "project_id", "name", "description", "pros", "cons", "risks", "status", "kill_reason", "created_at", "updated_at") VALUES (1, 2, 'Powertrain Arch A: CVT + RZR 570 (Selected)', 'Polaris RZR 570 engine mated to Comet 780 CVT with torque-sensing primary clutch. Single-stage chain reduction to rear diff.', 'Simple, proven, light. No clutch pedal. Reliable CVT belt life > 50h in competition.', 'Less driver feedback than manual. Belt replacement in field is slow.', 'Belt slip at high altitude — mitigated by clutch spring retuning.', 'selected', NULL, '2026-03-23T13:34:45.545Z', '2026-03-23T13:34:45.545Z') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_architectures" ("id", "project_id", "name", "description", "pros", "cons", "risks", "status", "kill_reason", "created_at", "updated_at") VALUES (2, 2, 'Powertrain Arch B: Manual Box + Briggs & Stratton', 'Briggs & Stratton 18hp engine with 5-speed sequential manual gearbox. Heavier but full driver control.', 'Direct driver feedback. Simpler repair. Lower parts cost.', 'Heavier by ~8kg. Driver fatigue on long courses. Less power.', 'Driver error on gear selection in rocky terrain.', 'active', NULL, '2026-03-23T13:34:46.058Z', '2026-03-23T13:34:46.058Z') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_architectures" ("id", "project_id", "name", "description", "pros", "cons", "risks", "status", "kill_reason", "created_at", "updated_at") VALUES (3, 1, 'Config A: Fixed Quadcopter with Folding Arms', 'Standard X-frame quad with folding arms for transport. Pixhawk 6X + T-Motor F90 propulsion. Best for vertical ISR missions.', 'Simple, reliable, proven airframe. Easy maintenance. GPS-denied nav possible.', 'Lower max speed than hybrid VTOL. Limited payload bay volume.', 'Arm hinge fatigue after 200+ deployments.', 'active', NULL, '2026-03-23T13:34:46.556Z', '2026-03-23T13:34:46.556Z') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_architectures" ("id", "project_id", "name", "description", "pros", "cons", "risks", "status", "kill_reason", "created_at", "updated_at") VALUES (4, 1, 'Config B: Tilt-Rotor VTOL Hybrid', 'Fixed-wing cruise with tilting front rotors for VTOL. 3x range of quad config. Significantly more complex mechanically.', 'Extended range (45km vs 12km). Higher cruise speed. Better wind resistance.', 'Complex tilt mechanism. 6-month longer development. Higher crash risk.', 'Tilt actuator failure in hover = unrecoverable crash.', 'active', NULL, '2026-03-23T13:34:47.071Z', '2026-03-23T13:34:47.071Z') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_architectures" ("id", "project_id", "name", "description", "pros", "cons", "risks", "status", "kill_reason", "created_at", "updated_at") VALUES (5, 22, 'Series-Parallel Hybrid with Full Regen (Selected)', 'Cummins ISX12N + 150kW electric motor on transmission input. 11kWh LFP pack. Supports 15% grade on electric-only and full regen on all service braking.', '40% better fuel economy in stop-go routes. Meets 2030 fleet emissions targets. Lower TCO at 5+ years.', 'Higher upfront cost (+$42k). Longer delivery lead time. Complex BMS integration.', 'Motor-to-PTO interface tolerance stacking. Battery cooling undersized for desert routes.', 'selected', NULL, '2026-03-23T13:34:47.578Z', '2026-03-23T13:34:47.578Z') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_architectures" ("id", "project_id", "name", "description", "pros", "cons", "risks", "status", "kill_reason", "created_at", "updated_at") VALUES (6, 22, 'Mild Hybrid: 48V Belt-Starter Generator', '48V BSG integrated to engine accessory drive. ~15kW regeneration, no electric-only mode. Much simpler integration.', 'Half the cost. Proven technology. No high-voltage safety certification needed.', 'Only 8-12% fuel savings vs 35-40% for full hybrid. No electric-only city mode.', 'Insufficient fuel savings to meet fleet buyer ROI thresholds.', 'active', NULL, '2026-03-23T13:34:48.081Z', '2026-03-23T13:34:48.081Z') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_architectures" ("id", "project_id", "name", "description", "pros", "cons", "risks", "status", "kill_reason", "created_at", "updated_at") VALUES (7, 1, 'Config A: Fixed Quadcopter with Folding Arms', 'Standard X-frame quad with folding arms for transport. Pixhawk 6X + T-Motor F90 propulsion. Best for vertical ISR missions.', 'Simple, reliable, proven airframe. Easy maintenance. GPS-denied nav possible.', 'Lower max speed than hybrid VTOL. Limited payload bay volume.', 'Arm hinge fatigue after 200+ deployments.', 'active', NULL, '2026-03-23T13:55:41.341Z', '2026-03-23T13:55:41.341Z') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_architectures" ("id", "project_id", "name", "description", "pros", "cons", "risks", "status", "kill_reason", "created_at", "updated_at") VALUES (8, 1, 'Config B: Tilt-Rotor VTOL Hybrid', 'Fixed-wing cruise with tilting front rotors for VTOL. 3× range of quad config. Significantly more complex mechanically.', 'Extended range (45km vs 12km). Higher cruise speed. Better wind resistance.', 'Complex tilt mechanism. 6-month longer development. Higher crash risk.', 'Tilt actuator failure in hover = unrecoverable crash.', 'active', NULL, '2026-03-23T13:55:41.394Z', '2026-03-23T13:55:41.394Z') ON CONFLICT DO NOTHING;
