INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (1, 2, 'Polaris RZR 570 Engine (44hp)', NULL, 'candidate_part', 'formal', 'high', '["powertrain","engine","proven"]', '2026-03-23T13:30:43.685Z', '2026-03-23T13:30:43.685Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (2, 2, 'Comet 780 Series CVT', 'Continuously variable transmission matched to RZR 570 power band. 30% reduction in shifting losses vs manual box.', 'candidate_part', 'promotable', 'high', '["powertrain","transmission","cvt"]', '2026-03-23T13:31:05.353Z', '2026-03-23T13:31:05.353Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (3, 2, 'CVT vs Manual Gearbox Selection', 'Trade study evaluating CVT (Comet 780) vs a sequential manual box. CVT wins on weight and simplicity; manual wins on driver control.', 'trade_study', 'repeatable', 'medium', '["trade-study","powertrain","transmission"]', '2026-03-23T13:31:05.865Z', '2026-03-23T13:31:05.865Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (4, 2, 'Engine-to-CVT Mounting Interface Geometry', 'Hypothesis: welded cradle with 4-point isolation mounts. Needs FEA to confirm load paths through engine cross-rail.', 'interface_hypothesis', 'raw', 'low', '["interface","mounting","powertrain"]', '2026-03-23T13:31:20.512Z', '2026-03-23T13:31:20.512Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (5, 2, 'CVT Belt Slip at Peak Load on Hill Climb', 'Observed: belt slips when engine hits 7200 RPM on steep incline. Root cause suspected to be spring preload. Retuning primary clutch spring rate.', 'observation', 'repeatable', 'medium', '["failure","cvt","testing"]', '2026-03-23T13:31:21.008Z', '2026-03-23T13:31:21.008Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (6, 2, 'Double A-Arm Front Suspension', 'Unequal-length double A-arm with 10" travel. Geometry optimized for camber gain. Fabricated 4130 chromoly arms.', 'mechanism', 'formal', 'high', '["suspension","front","mechanism"]', '2026-03-23T13:31:21.507Z', '2026-03-23T13:31:21.507Z', NULL, NULL, NULL, NULL, 'suspension') ON CONFLICT DO NOTHING;
