INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (46, 2, 'Steel vs Chromoly Frame Material', 'DOM 1018 steel vs 4130 chromoly trade study. Chromoly saves ~3.2kg but costs 2.4× more. Decision: chromoly for main hoop, DOM elsewhere.', 'trade_study', 'formal', 'high', '["material","frame","chassis"]', '2026-03-23T13:57:03.396Z', '2026-03-23T13:57:03.396Z', NULL, NULL, NULL, NULL, 'chassis') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (47, 2, 'Ergonomic Driver Cell Packaging', 'Concept: tight-package cockpit for 5th–95th percentile driver. Harness angle, pedal box reach, and steering column tilt still TBD.', 'concept', 'raw', 'low', '["ergonomics","chassis","driver"]', '2026-03-23T13:57:03.446Z', '2026-03-23T13:57:03.446Z', NULL, NULL, NULL, NULL, 'chassis') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (48, 22, 'Parallel Hybrid Drivetrain Architecture', 'Engine and electric motor both drive the transmission input shaft via planetary gear set. Enables regen braking and electric-only low-speed operation.', 'concept', 'formal', 'high', '["powertrain","hybrid","architecture"]', '2026-03-23T13:57:16.557Z', '2026-03-23T13:57:16.557Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (49, 22, 'Cummins ISX12N Natural Gas Engine (400hp)', 'Natural gas variant of ISX12. 400hp / 1450 lb-ft. Meets EPA 2027 NOx without SCR. Drop-in for diesel ISX12 packaging.', 'candidate_part', 'formal', 'high', '["engine","powertrain","natural-gas"]', '2026-03-23T13:57:16.606Z', '2026-03-23T13:57:16.606Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (50, 22, 'Regenerative Braking Integration with ABS', 'Blended braking: ABS module splits regen torque from hydraulic brakes to prevent wheel lockup. Bosch iBooster interface needed.', 'mechanism', 'repeatable', 'medium', '["braking","regen","powertrain"]', '2026-03-23T13:57:16.655Z', '2026-03-23T13:57:16.655Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (51, 22, 'Electric Motor to Transmission PTO Shaft Interface', 'Hypothesis: SAE #3 PTO mount with custom spline adapter. Motor centreline offset 45mm from transmission axis. Needs tolerance stack analysis.', 'interface_hypothesis', 'raw', 'low', '["interface","motor","powertrain"]', '2026-03-23T13:57:16.704Z', '2026-03-23T13:57:16.704Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (52, 22, 'Regen Braking Recovery Efficiency at 60mph', 'Dyno test: regen recovered 62% of kinetic energy at 60→0mph stop. Target was 65%. ABS limiting recovery window by 80ms. Investigating.', 'experiment', 'repeatable', 'medium', '["test","regen","efficiency"]', '2026-03-23T13:57:16.754Z', '2026-03-23T13:57:16.754Z', NULL, NULL, NULL, NULL, 'powertrain') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (53, 22, 'CATL LFP 105Ah Battery Module (×16)', '3.2V LFP prismatic cells. 16 modules in 2P8S configuration → 51.2V nominal, 210Ah. ~11kWh usable. Rated for 3000 cycles to 80% SOH.', 'candidate_part', 'promotable', 'high', '["battery","energy-storage","lfp"]', '2026-03-23T13:57:16.803Z', '2026-03-23T13:57:16.803Z', NULL, NULL, NULL, NULL, 'energy_storage') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (54, 22, 'LFP vs NMC Battery Chemistry Trade Study', 'LFP: safer, longer cycle life, lower cost, heavier. NMC: higher energy density, shorter life, thermal runaway risk. LFP selected for commercial fleet duty cycle.', 'trade_study', 'formal', 'high', '["trade-study","battery","chemistry"]', '2026-03-23T13:57:16.855Z', '2026-03-23T13:57:16.855Z', NULL, NULL, NULL, NULL, 'energy_storage') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (55, 22, 'Battery Thermal Runaway Risk at 50°C Ambient', 'Observation: cells reached 61°C surface temp in Phoenix summer testing at 2C discharge rate. LFP thermal runway threshold ~130°C — margin OK but cooling system undersized.', 'observation', 'repeatable', 'medium', '["thermal","battery","safety"]', '2026-03-23T13:57:16.905Z', '2026-03-23T13:57:16.905Z', NULL, NULL, NULL, NULL, 'energy_storage') ON CONFLICT DO NOTHING;
INSERT INTO "discovery_objects" ("id", "project_id", "title", "description", "type", "maturity", "confidence", "tags", "created_at", "updated_at", "created_by", "promoted_node_id", "promoted_at", "promoted_by", "functional_cluster") VALUES (56, 22, 'Hybrid Power Management Controller', 'Functional chunk: embedded controller arbitrating engine torque, motor torque, regen events, and battery SOC targets. Runs on dedicated ECU, 10ms cycle time.', 'functional_chunk', 'promotable', 'medium', '["controls","hybrid","energy-management"]', '2026-03-23T13:57:16.954Z', '2026-03-23T13:57:16.954Z', NULL, NULL, NULL, NULL, 'energy_storage') ON CONFLICT DO NOTHING;
